# Convert a curated trajectory to few-shot example messages.
# The messages are prepended to the system or user prompt as examples.

def trajectory_to_few_shot_messages(traj: Trajectory) -> list[dict]:
    """
    Convert a trajectory into the message format expected by the model API.
    Tool call steps become assistant messages with tool_use content blocks;
    tool result steps become user messages with tool_result content blocks.
    """
    messages = [{"role": "user", "content": traj.user_input}]

    i = 0
    while i < len(traj.steps):
        step = traj.steps[i]

        if step.step_type == "thought":
            messages.append({"role": "assistant", "content": step.content})

        elif step.step_type == "tool_call":
            messages.append({
                "role": "assistant",
                "content": [{
                    "type": "tool_use",
                    "id": f"ex_call_{i}",
                    "name": step.tool_name,
                    "input": step.tool_input,
                }],
            })

        elif step.step_type == "tool_result":
            messages.append({
                "role": "user",
                "content": [{
                    "type": "tool_result",
                    "tool_use_id": f"ex_call_{i - 1}",
                    "content": str(step.tool_output),
                }],
            })

        elif step.step_type == "final_output":
            messages.append({"role": "assistant", "content": step.content})

        i += 1

    return messages
